using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
int n,a[71],sum,m,cnt,ans;
bool use[71];
bool cmp(int x,int y)
{
	return x>y;
}
void dfs(int now,int nlg,int last)
{
	if(now>cnt)
	{
		cout<<ans;
		exit(0);
	}
	if(nlg==ans)
	{
		dfs(now+1,0,-1);
		return;
	}
	int f=0;
	for(int i=last+1;i<=n;i++)
	{
		if(!(use[i]||nlg+a[i]>ans||f==a[i]))
		{
			use[i]=1;
			dfs(now,nlg+a[i],i);
			use[i]=0;
			f=a[i];
			if(nlg==0||nlg+a[i]==ans)return;
		}
	}
}
signed main(void)
{
	cin>>n;
	for(int i=1;i<=n;i++)a[i]=read(),sum+=a[i],m=max(m,a[i]);
	sort(a+1,a+n+1,cmp);
	for(int i=m;i<=sum/2;i++)
	{
		if(sum%i==0)
		{
			memset(use,0,sizeof(use));
			cnt=sum/i,ans=i;
			dfs(1,0,-1);
		}
	}
	cout<<sum<<endl;
	return false;
}
